function createDataSource(exampleCase: ExampleCase) {
  const content = `${JSON.stringify(exampleCase.payload)}\n`

  return {
    path: `s3://qa-huawei/example/${exampleCase.id}.jsonl?bytes=0,${content.length}`,
    type: 'file' as const,
    created_by: null,
    mimetype: 'application/x-ndjson',
    size: content.length,
    content,
    last_modified: '2026-04-14T10:56:53Z',
  }
}

export default function App() {
  const [activeExampleId, setActiveExampleId] = useState(exampleCases[0].id)

  const activeExample = useMemo(() => {
    return exampleCases.find(item => item.id === activeExampleId) ?? exampleCases[0]
  }, [activeExampleId])

  const dataSource = useMemo(() => createDataSource(activeExample), [activeExample])

  const handleParamsChange = (params: unknown) => {
    console.log('BucketBlock change:', params)
  }

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: '280px minmax(0, 1fr)',
        minHeight: '100vh',
        background: '#f8fafc',
        color: '#0f172a',
      }}
    >
      <aside
        style={{
          borderRight: '1px solid #e2e8f0',
          background: '#ffffff',
          padding: 20,
          display: 'flex',
          flexDirection: 'column',
          gap: 12,
        }}
      >
        <div>
          <h1 style={{ margin: '0 0 8px', fontSize: 18 }}>Vis3 JSON Examples</h1>
          <p style={{ margin: 0, fontSize: 13, lineHeight: 1.5, color: '#475569' }}>
            Use these fixtures to debug JSON key clicking, nested previews, and special path handling.
          </p>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {exampleCases.map(exampleCase => {
            const isActive = exampleCase.id === activeExample.id

            return (
              <button
                key={exampleCase.id}
                type="button"
                onClick={() => setActiveExampleId(exampleCase.id)}
                style={{
                  textAlign: 'left',
                  border: isActive ? '1px solid #2563eb' : '1px solid #cbd5e1',
                  background: isActive ? '#eff6ff' : '#ffffff',
                  borderRadius: 10,
                  padding: 12,
                  cursor: 'pointer',
                }}
              >
                <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 6 }}>
                  {exampleCase.title}
                </div>
                <div style={{ fontSize: 12, lineHeight: 1.5, color: '#475569' }}>
                  {exampleCase.description}
                </div>
              </button>
            )
          })}
        </div>
      </aside>

      <main style={{ padding: 20 }}>
        <div style={{ marginBottom: 16 }}>
          <h2 style={{ margin: '0 0 6px', fontSize: 20 }}>{activeExample.title}</h2>
          <p style={{ margin: 0, color: '#475569', fontSize: 14 }}>{activeExample.description}</p>
        </div>

        <BucketBlock
          id={activeExample.id}
          style={{ height: '90vh' }}
          dataSource={dataSource}
          path={`s3://qa-huawei/example/${activeExample.id}.jsonl`}
          onChange={handleParamsChange}
          showPagination={false}
          showDownload={false}
        />
      </main>
    </div>
  )
}